package cn.nobeta.dingdong.product.service;
import cn.nobeta.dingdong.product.api.ProductResponses.ProductDetail;import cn.nobeta.dingdong.product.mapper.ProductMapper;import com.fasterxml.jackson.databind.ObjectMapper;import org.junit.jupiter.api.Test;import org.springframework.data.redis.core.StringRedisTemplate;import org.springframework.data.redis.core.ValueOperations;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.Mockito.*;
class ProductDetailCacheServiceTest {@Test void returnsCachedDetailWithoutDatabaseLookup() throws Exception {StringRedisTemplate redis=mock(StringRedisTemplate.class);@SuppressWarnings("unchecked") ValueOperations<String,String> values=mock(ValueOperations.class);when(redis.opsForValue()).thenReturn(values);ProductDetail detail=new ProductDetail(1L,"缓存商品",null,null,null,1L,1L,1,java.util.List.of());ObjectMapper mapper=new ObjectMapper();when(values.get("dingdong:product:detail:1")).thenReturn(mapper.writeValueAsString(detail));ProductMapper productMapper=mock(ProductMapper.class);ProductDetail result=new ProductDetailCacheService(redis,mapper,productMapper).get(1L);assertEquals("缓存商品",result.title());verifyNoInteractions(productMapper);}}
